; 試練の迷宮

name = 試練の迷宮Ｂ６
insideName = Ｂ６
upper = 試練の迷宮Ｂ５
level = 50
bgm = labyrinth
isOutdoor = true
roof = stone
shadow = dark
sky = black
antiWarp = true

; 各パーツ
━ = stoner_h
　 = marble
☐ = marble
☆ = soilr
❑ = cube
／ = door
∫ = pick
☖ = arch
⧻ = fence
﹃ = ladder
︻ = panel
㊤ = ladderu
上 = ladderu
ⓐ = warp
⒉ = br_int
⒍ = monument

; 敵情報
maxGroups = 2
monsters = ダークサモナー,サンダーウィスプ,コールドウィスプ

; 移動ポイント
(A) = map:試練の迷宮Ｂ１, x:0, y:2, way:s

; 宝箱
box[1] = いやしの竪琴_u,スレイブバックラー_u,アマゾネスの鎧・下_u,コールポラリスの魔法書_u,ポラリスの宝珠,強力眠気ざまし
box[2] = 罠はない,とある冒険者のメモ,ジャンプの巻物,ジャンプの巻物
box[3] = 罠はない,加護のメダル,魔導士ラニガンの手紙

